<section class="cb-page-band"><?php while (have_posts()) : the_post(); ?><div class="cb-container"><?php if (function_exists('cb_breadcrumb')) cb_breadcrumb(); ?><div class="cb-detail-heading"><p class="cb-eyebrow"><?php echo esc_html(cb_theme_lang() === 'zh' ? '制造能力' : 'MANUFACTURING CAPABILITY'); ?></p><h1><?php the_title(); ?></h1><p><?php echo esc_html(get_the_excerpt()); ?></p></div><?php echo cb_theme_image(get_the_post_thumbnail_url(get_the_ID(), 'full'), get_the_title(), 'cb-detail-hero-image', 1400, 820); ?><article class="cb-content cb-longform-content"><?php the_content(); ?></article></div><?php endwhile; ?></section>
